using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class WeatherTools
{
    [McpServerTool, Description("Get current weather for a location by latitude and longitude.")]
    public static async Task<string> GetCurrentWeather(
        IHttpClientFactory httpClientFactory,
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        using var client = httpClientFactory.CreateClient("WeatherApi");

        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        var response = await client.GetFromJsonAsync<WeatherResponse>(url);

        if (response?.Current is null)
            return "Unable to retrieve weather data.";

        var c = response.Current;
        return $"Temperature: {c.Temperature}°C, Wind: {c.WindSpeed} km/h";
    }

    [McpServerTool, Description("Look up coordinates for a city name.")]
    public static async Task<string> GeocodeCityName(
        IHttpClientFactory httpClientFactory,
        [Description("City name to search for")] string city)
    {
        using var client = httpClientFactory.CreateClient("WeatherApi");

        var url = $"v1/search?name={Uri.EscapeDataString(city)}&count=1";
        var response = await client.GetFromJsonAsync<GeocodeResponse>(url);

        if (response?.Results is not [var first, ..])
            return $"No results found for '{city}'.";

        return $"{first.Name}: lat={first.Latitude}, lon={first.Longitude}";
    }
}

// --- JSON models ---

public record WeatherResponse(
    [property: JsonPropertyName("current")] CurrentWeather? Current);

public record CurrentWeather(
    [property: JsonPropertyName("temperature_2m")] double Temperature,
    [property: JsonPropertyName("wind_speed_10m")] double WindSpeed);

public record GeocodeResponse(
    [property: JsonPropertyName("results")] GeocodeResult[]? Results);

public record GeocodeResult(
    [property: JsonPropertyName("name")] string Name,
    [property: JsonPropertyName("latitude")] double Latitude,
    [property: JsonPropertyName("longitude")] double Longitude);

